// ServerInterface represents all server handlers.
type ServerInterface interface {
	// List the current user's conversations (updated_at DESC)
	// (GET /api/v1/advisor/conversations)
	ListAdvisorConversations(w http.ResponseWriter, r *http.Request, params ListAdvisorConversationsParams)
	// Get a conversation with all its turns (sequence ASC)
	// (GET /api/v1/advisor/conversations/{conversationId})
	GetAdvisorConversation(w http.ResponseWriter, r *http.Request, conversationId string)
	// Ask the advisor a natural-language question (opt-in)
	// (POST /api/v1/advisor/conversations:ask)
	AskAdvisor(w http.ResponseWriter, r *http.Request)
	// Current hash-chain head
	// (GET /api/v1/audit/head)
	GetAuditHead(w http.ResponseWriter, r *http.Request)
	// Verify a range of the audit chain (external verifier)
	// (POST /api/v1/audit/verify)
	VerifyAuditChain(w http.ResponseWriter, r *http.Request)
	// Local credential login
	// (POST /api/v1/auth/login)
	Login(w http.ResponseWriter, r *http.Request, params LoginParams)
	// Revoke refresh token and clear cookie
	// (POST /api/v1/auth/logout)
	LogoutAuth(w http.ResponseWriter, r *http.Request, params LogoutAuthParams)
	// Current session info
	// (GET /api/v1/auth/me)
	GetCurrentSession(w http.ResponseWriter, r *http.Request)
	// Rotate access token using refresh token
	// (POST /api/v1/auth/refresh)
	RefreshAuth(w http.ResponseWriter, r *http.Request, params RefreshAuthParams)
	// OIDC authorization-code callback (state + code via query string)
	// (GET /api/v1/auth/sso/{providerId}/callback)
	CompleteSSOLoginOIDC(w http.ResponseWriter, r *http.Request, providerId string, params CompleteSSOLoginOIDCParams)
	// Begin SSO login flow (returns IdP redirect URL or 302)
	// (GET /api/v1/auth/sso/{providerId}/login)
	StartSSOLogin(w http.ResponseWriter, r *http.Request, providerId string, params StartSSOLoginParams)
	// SAML SP-initiated POST binding endpoint (Assertion Consumer Service)
	// (POST /api/v1/auth/sso/{providerId}/saml/acs)
	CompleteSSOLoginSAML(w http.ResponseWriter, r *http.Request, providerId string)
	// List automatic backup archives
	// (GET /api/v1/backups)
	ListBackups(w http.ResponseWriter, r *http.Request)
	// Download a backup archive
	// (GET /api/v1/backups/{filename}/download)
	DownloadBackup(w http.ResponseWriter, r *http.Request, filename string)
	// List compliance profiles for the current tenant
	// (GET /api/v1/compliance/profiles)
	ListComplianceProfiles(w http.ResponseWriter, r *http.Request)
	// Activate a compliance framework
	// (POST /api/v1/compliance/profiles)
	CreateComplianceProfile(w http.ResponseWriter, r *http.Request)
	// List snapshots for a profile (created_at DESC)
	// (GET /api/v1/compliance/profiles/{profileId}/snapshots)
	ListComplianceSnapshots(w http.ResponseWriter, r *http.Request, profileId string, params ListComplianceSnapshotsParams)
	// Generate a snapshot from a scan session
	// (POST /api/v1/compliance/profiles/{profileId}/snapshots)
	GenerateComplianceSnapshot(w http.ResponseWriter, r *http.Request, profileId string)
	// Trigger insight detectors for a fleet (drift/anomaly/peer)
	// (POST /api/v1/fleets/{fleetId}/insights:run)
	RunFleetInsights(w http.ResponseWriter, r *http.Request, fleetId string)
	// List active (non-dismissed) insights
	// (GET /api/v1/insights)
	ListInsights(w http.ResponseWriter, r *http.Request, params ListInsightsParams)
	// Mark an insight as dismissed
	// (POST /api/v1/insights/{insightId}:dismiss)
	DismissInsight(w http.ResponseWriter, r *http.Request, insightId string)
	// List invitations for the current tenant (pending + accepted + expired)
	// (GET /api/v1/invitations)
	ListInvitations(w http.ResponseWriter, r *http.Request)
	// Create a tenant invitation (admin)
	// (POST /api/v1/invitations)
	CreateInvitation(w http.ResponseWriter, r *http.Request)
	// Preview an invitation by token (unauthenticated)
	// (GET /api/v1/invitations/by-token/{token})
	GetInvitationByToken(w http.ResponseWriter, r *http.Request, token string)
	// Accept an invitation (creates user + assigns role)
	// (POST /api/v1/invitations/by-token/{token}/accept)
	AcceptInvitation(w http.ResponseWriter, r *http.Request, token string)
	// Revoke an invitation (immediately marks expired)
	// (DELETE /api/v1/invitations/{invitationId})
	RevokeInvitation(w http.ResponseWriter, r *http.Request, invitationId string)
	// License metadata (E24)
	// (GET /api/v1/license)
	GetLicenseInfo(w http.ResponseWriter, r *http.Request)
	// Built-in + tenant 벤치마크 팩 목록 (E12 Stage 3)
	// (GET /api/v1/packs)
	ListPacks(w http.ResponseWriter, r *http.Request)
	// 단일 벤치마크 팩 + checks 상세 (E12 Stage 5)
	// (GET /api/v1/packs/{packKey})
	GetPack(w http.ResponseWriter, r *http.Request, packKey string)
	// 단일 check 상세 (audit cmd + eval rule + rationale + fix) (E12 Stage 6)
	// (GET /api/v1/packs/{packKey}/checks/{checkId})
	GetCheck(w http.ResponseWriter, r *http.Request, packKey string, checkId string)
	// 단일 check의 selftest fixture (E12 Stage 7)
	// (GET /api/v1/packs/{packKey}/checks/{checkId}/selftest)
	GetCheckSelftest(w http.ResponseWriter, r *http.Request, packKey string, checkId string)
	// List reports
	// (GET /api/v1/reports)
	ListReports(w http.ResponseWriter, r *http.Request, params ListReportsParams)
	// Verify the signature of a report
	// (POST /api/v1/reports/{reportId}:verify)
	VerifyReport(w http.ResponseWriter, r *http.Request, reportId string)
	// List robots
	// (GET /api/v1/robots)
	ListRobots(w http.ResponseWriter, r *http.Request, params ListRobotsParams)
	// Register a robot
	// (POST /api/v1/robots)
	CreateRobot(w http.ResponseWriter, r *http.Request, params CreateRobotParams)
	// Get a robot
	// (GET /api/v1/robots/{robotId})
	GetRobot(w http.ResponseWriter, r *http.Request, robotId string)
	// List scan sessions
	// (GET /api/v1/scans)
	ListScans(w http.ResponseWriter, r *http.Request, params ListScansParams)
	// Start a new scan session
	// (POST /api/v1/scans)
	CreateScan(w http.ResponseWriter, r *http.Request, params CreateScanParams)
	// Stream scan progress (WebSocket upgrade)
	// (GET /api/v1/scans/{sessionId}/progress)
	StreamScanProgress(w http.ResponseWriter, r *http.Request, sessionId string)
	// List SSO providers for the current tenant
	// (GET /api/v1/sso/providers)
	ListSSOProviders(w http.ResponseWriter, r *http.Request)
	// Register a new SSO provider (OIDC or SAML)
	// (POST /api/v1/sso/providers)
	CreateSSOProvider(w http.ResponseWriter, r *http.Request)
	// Delete an SSO provider (hard delete + audit emit)
	// (DELETE /api/v1/sso/providers/{providerId})
	DeleteSSOProvider(w http.ResponseWriter, r *http.Request, providerId string)
	// Get an SSO provider
	// (GET /api/v1/sso/providers/{providerId})
	GetSSOProvider(w http.ResponseWriter, r *http.Request, providerId string)
	// Update an SSO provider (partial — name/enabled/config independently optional)
	// (PUT /api/v1/sso/providers/{providerId})
	UpdateSSOProvider(w http.ResponseWriter, r *http.Request, providerId string)
	// Current tenant
	// (GET /api/v1/tenants/current)
	GetCurrentTenant(w http.ResponseWriter, r *http.Request)
	// List webhook endpoints for the current tenant
	// (GET /api/v1/webhooks)
	ListWebhookEndpoints(w http.ResponseWriter, r *http.Request)
	// Register a new webhook endpoint
	// (POST /api/v1/webhooks)
	CreateWebhookEndpoint(w http.ResponseWriter, r *http.Request)
	// Delete a webhook endpoint (deliveries are preserved — append-only)
	// (DELETE /api/v1/webhooks/{endpointId})
	DeleteWebhookEndpoint(w http.ResponseWriter, r *http.Request, endpointId string)
	// Get a webhook endpoint
	// (GET /api/v1/webhooks/{endpointId})
	GetWebhookEndpoint(w http.ResponseWriter, r *http.Request, endpointId string)
	// Update a webhook endpoint (URL · secret · events · format · enabled)
	// (PUT /api/v1/webhooks/{endpointId})
	UpdateWebhookEndpoint(w http.ResponseWriter, r *http.Request, endpointId string)
	// List delivery attempts for a webhook endpoint (created_at DESC)
	// (GET /api/v1/webhooks/{endpointId}/deliveries)
	ListWebhookDeliveries(w http.ResponseWriter, r *http.Request, endpointId string, params ListWebhookDeliveriesParams)
	// Send a one-off ping to a webhook endpoint (E29)
	// (POST /api/v1/webhooks/{endpointId}/test)
	TestWebhookEndpoint(w http.ResponseWriter, r *http.Request, endpointId string)
	// Liveness probe
	// (GET /healthz)
	GetHealthz(w http.ResponseWriter, r *http.Request)
	// Readiness probe
	// (GET /readyz)
	GetReadyz(w http.ResponseWriter, r *http.Request)
}

